          loadBalancer.acceptResolvedAddresses(ResolvedAddresses.newBuilder()
              .setAddresses(Collections.emptyList())
              .setAttributes(Attributes.newBuilder()
                .set(io.grpc.xds.XdsAttributes.XDS_CONFIG, xdsConfig.getValue())
