  private void verifyEdsPriorityNames(List<String> want, List<LocalityLbEndpoints>... updates) {
    Iterator<ClusterLoadAssignment> edsUpdates = Arrays.asList(updates).stream()
        .map(update -> ClusterLoadAssignment.newBuilder()
